#include <iostream>
#include <iomanip>
#include <cmath>
using namespace std;

int main() {
    double x;
    int n;
    cin >> x >> n;

    double s = sin(x);

    // Check if s == 1 to avoid division by zero (geometric series formula)
    // For s == 1, sum would be n, but constraints say s != 1.

    // Sum of geometric series: a*(1 - r^n)/(1 - r), where a = r = s
    // So sum = s * (1 - pow(s, n)) / (1 - s)

    double sum;
    if (fabs(s - 1.0) < 1e-12) {
        sum = n; // theoretical case, not expected per constraints
    } else {
        sum = s * (1.0 - pow(s, n)) / (1.0 - s);
    }

    cout << fixed << setprecision(3) << sum << endl;

    return 0;
}
